import{_ as o,c as r,o as t,a1 as a}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Gouvernance de quota : Protection Quota et Warmup | Antigravity-Manager","description":"Apprendre le mécanisme de gouvernance de quota d'Antigravity-Manager. Utiliser Quota Protection pour protéger les modèles par seuil, Smart Warmup pour préchauffage automatique, supportant analyse planifiée et contrôle de refroidissement.","frontmatter":{"title":"Gouvernance de quota : Protection Quota et Warmup | Antigravity-Manager","subtitle":"Gouvernance de quota : Protection Quota et Warmup | Antigravity-Manager","sidebarTitle":"Protégez vos quotas de modèles","description":"Apprendre le mécanisme de gouvernance de quota d'Antigravity-Manager. Utiliser Quota Protection pour protéger les modèles par seuil, Smart Warmup pour préchauffage automatique, supportant analyse planifiée et contrôle de refroidissement.","tags":["quota","warmup","comptes","proxy"],"prerequisite":["start-add-account","start-proxy-and-first-client"],"order":5},"headers":[],"relativePath":"fr/lbjlaq/Antigravity-Manager/advanced/quota/index.md","filePath":"fr/lbjlaq/Antigravity-Manager/advanced/quota/index.md"}`),n={name:"fr/lbjlaq/Antigravity-Manager/advanced/quota/index.md"};function i(s,e,u,d,c,l){return t(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="gouvernance-de-quota-combinaison-quota-protection-smart-warmup" tabindex="-1">Gouvernance de quota : combinaison Quota Protection + Smart Warmup <a class="header-anchor" href="#gouvernance-de-quota-combinaison-quota-protection-smart-warmup" aria-label="Permalink to &quot;Gouvernance de quota : combinaison Quota Protection + Smart Warmup&quot;">​</a></h1><p>Vous utilisez Antigravity Tools comme proxy depuis un moment, assez stable, mais vous craignez une chose : le quota du modèle principal est &quot;silencieusement épuisé&quot;, et quand vous voulez vraiment l&#39;utiliser, vous découvrez qu&#39;il est déjà trop bas pour être utilisable.</p><p>Ce cours traite spécifiquement de <strong>gouvernance de quota</strong> : utiliser Quota Protection pour garder les modèles clés ; utiliser Smart Warmup pour faire une &quot;préchauffage léger&quot; quand le quota revient à 100%, réduisant les interruptions temporaires.</p><h2 id="qu-est-ce-que-la-gouvernance-de-quota" tabindex="-1">Qu&#39;est-ce que la gouvernance de quota ? <a class="header-anchor" href="#qu-est-ce-que-la-gouvernance-de-quota" aria-label="Permalink to &quot;Qu&#39;est-ce que la gouvernance de quota ?&quot;">​</a></h2><p>La <strong>gouvernance de quota</strong> signifie utiliser deux mécanismes liés dans Antigravity Tools pour contrôler &quot;comment dépenser le quota&quot; : quand le quota restant d&#39;un certain modèle descend en dessous du seuil, Quota Protection ajoutera ce modèle aux <code>protected_models</code> du compte, et lors d&#39;une demande pour ce modèle, il sera prioritairement évité ; quand le quota revient à 100%, Smart Warmup déclenchera une demande de préchauffage à très faible trafic, et utilisera un fichier historique local pour 4 heures de refroidissement.</p><h2 id="ce-que-vous-pourrez-faire-apres-ce-cours" tabindex="-1">Ce que vous pourrez faire après ce cours <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-cours" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce cours&quot;">​</a></h2><ul><li>Activer Quota Protection, laisser les comptes à faible quota &quot;laisser la place&quot; automatiquement, gardant les modèles de haute valeur pour les requêtes clés</li><li>Activer Smart Warmup, préchauffer automatiquement quand le quota revient à 100% (et savoir comment 4 heures de refroidissement affectent la fréquence de déclenchement)</li><li>Clarifier où <code>quota_protection</code> / <code>scheduled_warmup</code> / <code>protected_models</code> prennent effet respectivement</li><li>Savoir quels noms de modèles seront normalisés en &quot;groupe de protection&quot; (et lesquels ne le seront pas)</li></ul><h2 id="votre-situation-actuelle" tabindex="-1">Votre situation actuelle <a class="header-anchor" href="#votre-situation-actuelle" aria-label="Permalink to &quot;Votre situation actuelle&quot;">​</a></h2><ul><li>Vous pensez être en &quot;rotation de comptes&quot;, mais en fait vous consommez toujours la même catégorie de modèles de haute valeur</li><li>Vous découvrez le quota bas seulement après, voire c&#39;est Claude Code/le client qui warmup en arrière-plan qui a mangé le quota</li><li>Vous avez activé le préchauffage, mais ne savez pas quand il se déclenche exactement, s&#39;il y a refroidissement, s&#39;il affectera le quota</li></ul><h2 id="quand-utiliser-cette-methode" tabindex="-1">Quand utiliser cette méthode <a class="header-anchor" href="#quand-utiliser-cette-methode" aria-label="Permalink to &quot;Quand utiliser cette méthode&quot;">​</a></h2><ul><li>Vous avez plusieurs pools de comptes, espérez qu&#39;aux &quot;moments importants&quot;, les modèles clés ont encore des réserves</li><li>Vous ne voulez pas surveiller manuellement l&#39;heure de retour du quota, voulez laisser le système faire &quot;vérification légère après retour&quot;</li></ul><h2 id="🎒-preparation-avant-de-commencer" tabindex="-1">🎒 Préparation avant de commencer <a class="header-anchor" href="#🎒-preparation-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparation avant de commencer&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Conditions préalables</p><p>Ce cours suppose que vous pouvez déjà :</p><ul><li>Voir la liste des comptes dans la page <strong>Accounts</strong>, et rafraîchir manuellement le quota</li><li>Avoir déjà démarré le reverse proxy local (au moins pouvoir accéder <code>/healthz</code>)</li></ul><p>Si vous n&#39;avez pas réussi, d&#39;abord voir <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Démarrer le reverse proxy local et intégrer le premier client</a></strong>.</p></div><p>De plus, Smart Warmup écrira le fichier historique local <code>warmup_history.json</code>. Il est placé dans le répertoire de données, l&#39;emplacement du répertoire de données et la méthode de sauvegarde peuvent d&#39;abord voir <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/start/first-run-data/">Premier démarrage à comprendre : répertoire de données, journaux, barre des tâches et démarrage automatique</a></strong>.</p><h2 id="idee-centrale" tabindex="-1">Idée centrale <a class="header-anchor" href="#idee-centrale" aria-label="Permalink to &quot;Idée centrale&quot;">​</a></h2><p>Derrière cette &quot;combinaison&quot; en fait très simple :</p><ul><li>Quota Protection fait &quot;ne plus gaspiller&quot; : quand un modèle descend sous le seuil, il est marqué comme protégé, lors d&#39;une demande pour ce modèle prioritairement évité (niveau modèle, pas interdiction globale du compte).</li><li>Smart Warmup fait &quot;vérifier dès que le quota revient&quot; : quand le modèle revient à 100%, déclencher une demande légère, confirmer que la chaîne est disponible, et utiliser 4 heures de refroidissement pour éviter d&#39;importuner à répétition.</li></ul><p>Les champs de configuration correspondants sont dans <code>AppConfig</code> du frontend :</p><ul><li><code>quota_protection.enabled / threshold_percentage / monitored_models</code> (voir <code>src/types/config.ts</code>)</li><li><code>scheduled_warmup.enabled / monitored_models</code> (voir <code>src/types/config.ts</code>)</li></ul><p>Et la logique qui décide vraiment &quot;lors d&#39;une demande à ce modèle, faut-il sauter ce compte&quot; est dans TokenManager backend :</p><ul><li><code>protected_models</code> dans le fichier compte participera au filtrage dans <code>get_token(..., target_model)</code> (voir <code>src-tauri/src/proxy/token_manager.rs</code>)</li><li><code>target_model</code> fera d&#39;abord une normalisation (<code>normalize_to_standard_id</code>), donc les variantes comme <code>claude-sonnet-4-5-thinking</code> seront repliées dans le même &quot;groupe de protection&quot; (voir <code>src-tauri/src/proxy/common/model_mapping.rs</code>)</li></ul><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Le prochain cours, nous apprenons <strong><a href="/docs/opencodedocs/fr/lbjlaq/Antigravity-Manager/advanced/monitoring/">Proxy Monitor : journaux de requêtes, filtrage, restauration de détails et exportation</a></strong>, transformant la boîte noire des appels en chaîne de preuves reproductible.</p></blockquote><h2 id="suivez-moi" tabindex="-1">Suivez-moi <a class="header-anchor" href="#suivez-moi" aria-label="Permalink to &quot;Suivez-moi&quot;">​</a></h2><h3 id="etape-1-d-abord-rafraichir-le-quota-a-des-donnees" tabindex="-1">Étape 1 : D&#39;abord rafraîchir le quota &quot;à des données&quot; <a class="header-anchor" href="#etape-1-d-abord-rafraichir-le-quota-a-des-donnees" aria-label="Permalink to &quot;Étape 1 : D&#39;abord rafraîchir le quota &quot;à des données&quot;&quot;">​</a></h3><p><strong>Pourquoi</strong> Quota Protection se base sur <code>quota.models[].percentage</code> du compte pour juger. Si vous n&#39;avez pas rafraîchi le quota, la logique de protection ne peut rien faire pour vous.</p><p>Chemin d&#39;opération : ouvrez la page <strong>Accounts</strong>, cliquez sur le bouton de rafraîchissement de la barre d&#39;outils (compte unique ou total vont).</p><p><strong>Ce que vous devriez voir</strong> : la ligne de compte affiche le pourcentage de quota de chaque modèle (par exemple 0-100) et l&#39;heure de reset.</p><h3 id="etape-2-dans-settings-activer-smart-warmup-optionnel-mais-recommande" tabindex="-1">Étape 2 : Dans Settings, activer Smart Warmup (optionnel, mais recommandé) <a class="header-anchor" href="#etape-2-dans-settings-activer-smart-warmup-optionnel-mais-recommande" aria-label="Permalink to &quot;Étape 2 : Dans Settings, activer Smart Warmup (optionnel, mais recommandé)&quot;">​</a></h3><p><strong>Pourquoi</strong> L&#39;objectif de Smart Warmup n&#39;est pas &quot;économiser le quota&quot;, mais &quot;vérifier la chaîne dès que le quota revient à 100%&quot;. Il ne se déclenche que quand le quota du modèle atteint 100%, et a 4 heures de refroidissement.</p><p>Chemin d&#39;opération : entrez dans <strong>Settings</strong>, basculez vers la zone de paramètres liés aux comptes, activez l&#39;interrupteur <strong>Smart Warmup</strong>, puis cochez les modèles que vous voulez surveiller.</p><p>N&#39;oubliez pas de sauvegarder les paramètres.</p><p><strong>Ce que vous devriez voir</strong> : Smart Warmup déployé montre la liste des modèles ; au moins conserver 1 modèle coché.</p><h3 id="etape-3-activer-quota-protection-et-definir-seuil-et-modeles-surveilles" tabindex="-1">Étape 3 : Activer Quota Protection, et définir seuil et modèles surveillés <a class="header-anchor" href="#etape-3-activer-quota-protection-et-definir-seuil-et-modeles-surveilles" aria-label="Permalink to &quot;Étape 3 : Activer Quota Protection, et définir seuil et modèles surveillés&quot;">​</a></h3><p><strong>Pourquoi</strong> Quota Protection est le cœur de &quot;garder des réserves&quot; : quand le pourcentage de quota des modèles surveillés <code>&lt;= threshold_percentage</code>, le modèle sera écrit dans <code>protected_models</code> du fichier compte, et les demandes ultérieures pour ce modèle éviteront prioritairement ces comptes.</p><p>Chemin d&#39;opération : dans <strong>Settings</strong>, activez <strong>Quota Protection</strong>.</p><ol><li>Définir le seuil (<code>1-99</code>)</li><li>Cochez les modèles que vous voulez surveiller (au moins 1)</li></ol><div class="tip custom-block"><p class="custom-block-title">Une configuration de départ très utile</p><p>Si vous ne voulez pas vous embêter, commencez par défaut <code>threshold_percentage=10</code> (voir <code>src/pages/Settings.tsx</code>).</p></div><p><strong>Ce que vous devriez voir</strong> : la sélection de modèles Quota Protection garde au moins 1 (l&#39;interface vous empêchera de décocher le dernier).</p><h3 id="etape-4-confirmer-que-normalisation-du-groupe-de-protection-ne-vous-posera-pas-probleme" tabindex="-1">Étape 4 : Confirmer que &quot;normalisation du groupe de protection&quot; ne vous posera pas problème <a class="header-anchor" href="#etape-4-confirmer-que-normalisation-du-groupe-de-protection-ne-vous-posera-pas-probleme" aria-label="Permalink to &quot;Étape 4 : Confirmer que &quot;normalisation du groupe de protection&quot; ne vous posera pas problème&quot;">​</a></h3><p><strong>Pourquoi</strong> Quand TokenManager fait le jugement de protection de quota, il va d&#39;abord normaliser <code>target_model</code> en ID standard (<code>normalize_to_standard_id</code>). Par exemple <code>claude-sonnet-4-5-thinking</code> sera normalisé en <code>claude-sonnet-4-5</code>.</p><p>Cela signifie :</p><ul><li>Vous cochez <code>claude-sonnet-4-5</code> dans Quota Protection</li><li>Quand vous demandez réellement <code>claude-sonnet-4-5-thinking</code></li></ul><p>Cela correspondra toujours à la protection (car ils appartiennent au même groupe).</p><p><strong>Ce que vous devriez voir</strong> : quand <code>protected_models</code> d&#39;un certain compte contient <code>claude-sonnet-4-5</code>, les demandes pour <code>claude-sonnet-4-5-thinking</code> éviteront prioritairement ce compte.</p><h3 id="etape-5-besoin-de-verifier-immediatement-utiliser-warmup-manuel-pour-declencher-un-warmup" tabindex="-1">Étape 5 : Besoin de vérifier immédiatement, utiliser &quot;warmup manuel&quot; pour déclencher un warmup <a class="header-anchor" href="#etape-5-besoin-de-verifier-immediatement-utiliser-warmup-manuel-pour-declencher-un-warmup" aria-label="Permalink to &quot;Étape 5 : Besoin de vérifier immédiatement, utiliser &quot;warmup manuel&quot; pour déclencher un warmup&quot;">​</a></h3><p><strong>Pourquoi</strong> La période de scan Smart Warmup programmé est toutes les 10 minutes (voir <code>src-tauri/src/modules/scheduler.rs</code>). Vous voulez vérifier la chaîne immédiatement, le warmup manuel est plus direct.</p><p>Chemin d&#39;opération : ouvrez la page <strong>Accounts</strong>, cliquez sur le bouton &quot;Préchauffage&quot; de la barre d&#39;outils :</p><ul><li>Pas de compte sélectionné : déclenche warmup total (appelle <code>warm_up_all_accounts</code>)</li><li>Compte sélectionné : déclenche warmup un par un pour les comptes sélectionnés (appelle <code>warm_up_account</code>)</li></ul><p><strong>Ce que vous devriez voir</strong> : un toast apparaît, le contenu vient de la chaîne renvoyée par le backend (par exemple &quot;Warmup task triggered ...&quot;).</p><h2 id="point-de-verification-✅" tabindex="-1">Point de vérification ✅ <a class="header-anchor" href="#point-de-verification-✅" aria-label="Permalink to &quot;Point de vérification ✅&quot;">​</a></h2><ul><li>Vous pouvez voir sur la page Accounts le pourcentage de quota de chaque compte de chaque modèle (prouve que la chaîne de données quota est OK)</li><li>Vous pouvez activer Quota Protection / Smart Warmup dans Settings, et sauvegarder avec succès la configuration</li><li>Vous comprenez que <code>protected_models</code> est une restriction &quot;niveau modèle&quot; : un compte peut être évité seulement pour certains modèles</li><li>Vous savez que warmup a 4 heures de refroidissement : répétition rapprochée de préchauffage, vous pourriez voir des indices &quot;skipped/cooldown&quot;</li></ul><h2 id="attention-aux-pieges-courants" tabindex="-1">Attention aux pièges courants <a class="header-anchor" href="#attention-aux-pieges-courants" aria-label="Permalink to &quot;Attention aux pièges courants&quot;">​</a></h2><h3 id="_1-vous-avez-active-quota-protection-mais-ca-n-a-jamais-pris-effet" tabindex="-1">1) Vous avez activé Quota Protection, mais ça n&#39;a jamais pris effet <a class="header-anchor" href="#_1-vous-avez-active-quota-protection-mais-ca-n-a-jamais-pris-effet" aria-label="Permalink to &quot;1) Vous avez activé Quota Protection, mais ça n&#39;a jamais pris effet&quot;">​</a></h3><p>La cause la plus fréquente : le compte n&#39;a pas de données <code>quota</code>. La logique de protection dans le backend doit d&#39;abord lire <code>quota.models[]</code> pour juger le seuil (voir <code>src-tauri/src/proxy/token_manager.rs</code>).</p><p>Vous pouvez revenir à <strong>l&#39;étape 1</strong>, d&#39;abord rafraîchir le quota.</p><h3 id="_2-pourquoi-seulement-quelques-modeles-seront-consideres-comme-groupe-de-protection" tabindex="-1">2) Pourquoi seulement quelques modèles seront considérés comme &quot;groupe de protection&quot; ? <a class="header-anchor" href="#_2-pourquoi-seulement-quelques-modeles-seront-consideres-comme-groupe-de-protection" aria-label="Permalink to &quot;2) Pourquoi seulement quelques modèles seront considérés comme &quot;groupe de protection&quot; ?&quot;">​</a></h3><p>La normalisation par TokenManager de <code>target_model</code> est &quot;liste blanche&quot; : seuls les noms de modèles explicitement listés seront mappés vers l&#39;ID standard (voir <code>src-tauri/src/proxy/common/model_mapping.rs</code>).</p><p>La logique après normalisation est : utiliser le nom normalisé (ID standard ou nom de modèle original) pour correspondre au champ <code>protected_models</code> du compte. Si la correspondance réussit, le compte sera sauté (voir <code>src-tauri/src/proxy/token_manager.rs:555-560, 716-719</code>). Cela signifie :</p><ul><li>Les modèles dans la liste blanche (comme <code>claude-sonnet-4-5-thinking</code>) seront normalisés en ID standard (<code>claude-sonnet-4-5</code>), puis juger s&#39;ils sont dans <code>protected_models</code></li><li>Quand la normalisation échoue pour les modèles hors liste blanche, revenir au nom de modèle original, toujours correspondre à <code>protected_models</code></li></ul><p>En d&#39;autres termes, le jugement de protection de quota prend effet pour &quot;tous les noms de modèles&quot;, juste que les modèles dans la liste blanche seront d&#39;abord normalisés.</p><h3 id="_3-pourquoi-warmup-manuel-programme-a-besoin-que-le-proxy-tourne" tabindex="-1">3) Pourquoi warmup manuel/programmé a besoin que le proxy tourne ? <a class="header-anchor" href="#_3-pourquoi-warmup-manuel-programme-a-besoin-que-le-proxy-tourne" aria-label="Permalink to &quot;3) Pourquoi warmup manuel/programmé a besoin que le proxy tourne ?&quot;">​</a></h3><p>La demande de warmup finira par toucher le point de terminaison interne du proxy local : <code>POST /internal/warmup</code> (voir la route dans <code>src-tauri/src/proxy/server.rs</code>, et l&#39;implémentation dans <code>src-tauri/src/proxy/handlers/warmup.rs</code>). Si vous n&#39;avez pas démarré le service proxy, warmup échouera.</p><p>De plus, le port appelé par le préchauffage vient de la configuration : <code>proxy.port</code> (si la lecture de la configuration échoue, reviendra à <code>8045</code>, voir <code>src-tauri/src/modules/quota.rs</code>).</p><h2 id="resume-du-cours" tabindex="-1">Résumé du cours <a class="header-anchor" href="#resume-du-cours" aria-label="Permalink to &quot;Résumé du cours&quot;">​</a></h2><ul><li>Quota Protection fait &quot;arrêter la perte&quot; : sous le seuil, écrire le modèle dans <code>protected_models</code>, lors d&#39;une demande pour ce modèle éviter prioritairement</li><li>Smart Warmup fait &quot;vérification automatique après retour&quot; : se déclenche seulement à 100%, scanne une fois toutes les 10 minutes, 4 heures de refroidissement</li><li>Les deux dépendent de la chaîne &quot;rafraîchissement quota&quot; : d&#39;abord avoir <code>quota.models[]</code>, la gouvernance a une base</li></ul><h2 id="apercu-du-prochain-cours-1" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours-1" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><p>La gouvernance de quota résout &quot;comment dépenser plus stable&quot;. Le prochain cours suggère ensuite de voir <strong>Proxy Monitor</strong>, transformer journaux de requêtes, sélection de compte, mappage de modèle en chaîne de preuves reproductible.</p><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour développer les emplacements du code source</strong></summary><blockquote><p>Date de mise à jour : 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Ligne</th></tr></thead><tbody><tr><td>Interface Quota Protection (seuil, cocher modèles, au moins 1)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/QuotaProtection.tsx#L13-L168" target="_blank" rel="noreferrer"><code>src/components/settings/QuotaProtection.tsx</code></a></td><td>13-168</td></tr><tr><td>Interface Smart Warmup (activé par défaut coché, au moins 1)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/SmartWarmup.tsx#L14-L120" target="_blank" rel="noreferrer"><code>src/components/settings/SmartWarmup.tsx</code></a></td><td>14-120</td></tr><tr><td>Champs configuration gouvernance quota (<code>quota_protection</code> / <code>scheduled_warmup</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/types/config.ts#L54-L94" target="_blank" rel="noreferrer"><code>src/types/config.ts</code></a></td><td>54-94</td></tr><tr><td>Seuil par défaut et configuration par défaut (<code>threshold_percentage: 10</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L20-L51" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>20-51</td></tr><tr><td>Écriture/restauration <code>protected_models</code> (jugement seuil et sauvegarde disque)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L254-L467" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>254-467</td></tr><tr><td>Filtrage protection quota côté demande (<code>get_token(..., target_model)</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L470-L674" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>470-674</td></tr><tr><td>Normalisation groupe de protection (<code>normalize_to_standard_id</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L230-L254" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>230-254</td></tr><tr><td>Scan planifié Smart Warmup (une fois toutes les 10 minutes + 4 heures refroidissement + <code>warmup_history.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L11-L221" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>11-221</td></tr><tr><td>Commandes warmup manuel (<code>warm_up_all_accounts</code> / <code>warm_up_account</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L167-L212" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>167-212</td></tr><tr><td>Implémentation warmup (appeler point de terminaison interne <code>/internal/warmup</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/quota.rs#L271-L512" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/quota.rs</code></a></td><td>271-512</td></tr><tr><td>Implémentation point de terminaison interne warmup (construire demande + appeler amont)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/warmup.rs#L3-L220" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/warmup.rs</code></a></td><td>3-220</td></tr></tbody></table></details>',71)])])}const q=o(n,[["render",i]]);export{m as __pageData,q as default};
